1	type Cell = [number, number];
2	
3	const NEIGHBORS_TO_REPRODUCE = 3;
4	
5	const NEIGHBOR_OFFSETS: Cell[] = [
6	  [-1, -1], [0, -1], [1, -1],
7	  [-1, 0], [1, 0],
8	  [-1, 1], [0, 1], [1, 1],
9	];
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  const survivors = cells.filter((cell) =>
13	    survives(countLiveNeighbors(cell, cells))
14	  );
15	  const births = birthCandidates(cells).filter(
16	    (cell) => countLiveNeighbors(cell, cells) === NEIGHBORS_TO_REPRODUCE
17	  );
18	  return [...survivors, ...births];
19	}
20	
21	function birthCandidates(cells: Cell[]): Cell[] {
22	  const deadNeighbors = cells
23	    .flatMap(neighborsOf)
24	    .filter((candidate) => !contains(cells, candidate));
25	  return unique(deadNeighbors);
26	}
27	
28	function unique(cells: Cell[]): Cell[] {
29	  const seen = new Map<string, Cell>();
30	  for (const cell of cells) {
31	    seen.set(keyOf(cell), cell);
32	  }
33	  return [...seen.values()];
34	}
35	
36	function keyOf([x, y]: Cell): string {
37	  return `${x},${y}`;
38	}
39	
40	function neighborsOf([x, y]: Cell): Cell[] {
41	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
42	}
43	
44	function contains(cells: Cell[], cell: Cell): boolean {
45	  return cells.some((other) => samePosition(other, cell));
46	}
47	
48	function samePosition([x, y]: Cell, [ox, oy]: Cell): boolean {
49	  return x === ox && y === oy;
50	}
51	
52	const MIN_NEIGHBORS_TO_SURVIVE = 2;
53	const MAX_NEIGHBORS_TO_SURVIVE = 3;
54	
55	function survives(neighborCount: number): boolean {
56	  return (
57	    neighborCount === MIN_NEIGHBORS_TO_SURVIVE ||
58	    neighborCount === MAX_NEIGHBORS_TO_SURVIVE
59	  );
60	}
61	
62	function countLiveNeighbors(cell: Cell, cells: Cell[]): number {
63	  return neighborsOf(cell).filter((neighbor) => contains(cells, neighbor))
64	    .length;
65	}
