1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("returns an empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("a single live cell (0,0) dies from underpopulation — []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells [(0,1),(1,1)] both die from underpopulation — []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("a live cell with 2 neighbors survives (Rule 2 survival)", () => {
15	    // (1,1) has live neighbors (0,0) and (1,0) → 2 neighbors → survives
16	    const result = nextGeneration([[0, 0], [1, 0], [1, 1]]);
17	    expect(result).toContainEqual([1, 1]);
18	  });
19	  it("a live cell with 3 neighbors survives (Rule 2 survival)", () => {
20	    // (1,1) has live neighbors (0,0),(1,0),(2,0) → 3 neighbors → survives
21	    const result = nextGeneration([[1, 1], [0, 0], [1, 0], [2, 0]]);
22	    expect(result).toContainEqual([1, 1]);
23	  });
24	  it("a live cell with more than 3 neighbors dies from overpopulation (Rule 3)", () => {
25	    // (1,1) has 4 live neighbors (0,0),(2,0),(0,2),(2,2) → dies
26	    const result = nextGeneration([[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]]);
27	    expect(result).not.toContainEqual([1, 1]);
28	  });
29	  it("a dead cell with exactly 3 neighbors becomes alive (Rule 4 reproduction)", () => {
30	    // dead cell (1,1) has live neighbors (0,0),(1,0),(0,1) → 3 → becomes alive
31	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
32	    expect(result).toContainEqual([1, 1]);
33	  });
34	  it("a block still life [(0,0),(1,0),(0,1),(1,1)] stays unchanged", () => {
35	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
36	    const result = nextGeneration(block);
37	    const sort = (cells: [number, number][]) =>
38	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
39	    expect(sort(result)).toEqual(sort(block));
40	  });
41	  it("a blinker [(0,0),(0,1),(0,2)] becomes [(-1,1),(0,1),(1,1)]", () => {
42	    const blinker: [number, number][] = [[0, 0], [0, 1], [0, 2]];
43	    const result = nextGeneration(blinker);
44	    const sort = (cells: [number, number][]) =>
45	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
46	    expect(sort(result)).toEqual(sort([[-1, 1], [0, 1], [1, 1]]));
47	  });
48	});
